(window.webpackJsonp=window.webpackJsonp||[]).push([[65],{692:function(r,n){r.exports='\x3c!-- \r\ntitle: 03-操作命令\r\nsort: \r\n--\x3e \r\n# 操作命令\r\n\r\n## REM 注释命令\r\n\r\n- 行内注释：%内容%       （不常用）\r\n\r\n  ```bat\r\n  echo hh %显示hh%\r\n  rem 这是一个注释\r\n  ```\r\n\r\n## Errorlevel 程序返回码\r\n\r\n> 用于判断上一条命令是否运行成功。\r\n>\r\n> 是一个变量，默认为0。\r\n>\r\n> 未成功运行为1。\r\n>\r\n> 找不到为9009\r\n>\r\n> `echo %errorlevel%`\r\n\r\n## Tittle 设置cmd标题\r\n\r\n- `tittle 这是一个标题`\r\n\r\n- `color 0b %设置颜色%`\r\n\r\n  > 0 = 黑色     8 = 灰色\r\n  >\r\n  > 1 = 蓝色     9 = 淡蓝色\r\n  >\r\n  > 2 = 绿色     A = 淡绿色\r\n  >\r\n  > 3 = 湖蓝色    B = 淡浅绿色\r\n  >\r\n  > 4 = 红色     C = 淡红色\r\n  >\r\n  > 5 = 紫色     D = 淡紫色\r\n  >\r\n  > 6 = 黄色     E = 淡黄色\r\n  >\r\n  > 7 = 白色     F = 亮白色\r\n\r\n## Call\r\n\r\n> `call 文件名` 执行过程中调用另一个批处理\r\n\r\n## setlocal 变量延迟\r\n\r\n> 所有变量会在执行前设定为初始值，\r\n>\r\n> 在执行过程中变量不会随修改而改变。\r\n>\r\n> 开启变量延迟：\r\n>\r\n> `setlocal enabledelayedexpansion`\r\n>\r\n> 引用变量需要使用：`!var!`\r\n\r\n## If 条件判断\r\n\r\n1. 参数\r\n\r\n   | 参数                     | 含义               |\r\n   | ------------------------ | ------------------ |\r\n   | `NOT`                    | 取反               |\r\n   | `ERRORLEVEL num cmd`     | 错误判断           |\r\n   | `str1 比较符 str2 cmd`   | 字符串判断         |\r\n   | `EXIST filename command` | 判断目录是否存在   |\r\n   | `DEFINED`                | 判断变量是否被赋值 |\r\n\r\n2. 例子\r\n\r\n   ```bat\r\n   if errorlevel 1 goto 1\r\n   if not errorlevel 1 echo success\r\n   \r\n   if /i "we hh"=="We Hh" echo 相同\r\n   \r\n   if EXIST autoexec.bat (echo 文件存在！) else echo 文件不存在\r\n   if not EXIST autoexec.bat echo 文件不存在！\r\n   ```\r\n\r\n## for 循环\r\n\r\n1. 参数\r\n\r\n   | 参数 | 含义           |\r\n   | ---- | -------------- |\r\n   | /l   | 设置步长       |\r\n   | /d   | 只匹配文件夹   |\r\n   | /r   | 递归           |\r\n   | /f   | 提取文件中文本 |\r\n\r\n2. 例子\r\n\r\n   ```bat\r\n   for %i in (c:\\*) do echo %i\t\t\t\t# 打印c盘中的文件\r\n   for %i in (1,2,3) do echo %i\t\t\t# 打印列表值\r\n   \r\n   for /l %i in (1,1,10) do (md test%i) / (start www.baidu.com)  \r\n   # (开始值，步长，结束值)\r\n   \r\n   for /d %i in (D:\\???) do echo %i\t\t# 只匹配文件夹\r\n   \r\n   for /r d:\\ %i in (*.txt) do echo %i \t# D盘中所有txt\r\n   ```\r\n\r\n\r\n## 获取路径\r\n\r\n```bat\r\n@echo off\r\necho 当前盘符：%~d0\r\necho 当前盘符和路径：%~dp0\r\necho 当前批处理全路径：%~f0\r\necho 当前盘符和路径的短文件名格式：%~sdp0\r\necho 当前CMD默认目录：%cd%\r\necho 目录中有空格也可以加入""避免找不到路径\r\necho 当前盘符："%~d0"\r\necho 当前盘符和路径："%~dp0"\r\necho 当前批处理全路径："%~f0"\r\necho 当前盘符和路径的短文件名格式："%~sdp0"\r\necho 当前CMD默认目录："%cd%"\r\n```\r\n\r\n'}}]);